using System.Diagnostics;
using TextAnalysis;

// Setup
var words = new[] { "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "benchmark", "performance", "analysis", "extraordinary", "simple", "complex" };
var rng = new Random(42);
var parts = new string[1000];
for (int i = 0; i < parts.Length; i++)
    parts[i] = words[rng.Next(words.Length)];
var analyzer = new TextAnalyzer(string.Join(' ', parts));

const int warmup = 100;
const int iterations = 100_000;

// Warmup
for (int i = 0; i < warmup; i++)
{
    analyzer.AverageWordLength();
    analyzer.WordLengthHistogram();
    analyzer.UniqueWordCount();
}

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Iterations: {iterations:N0}");
Console.WriteLine();

// Benchmark AverageWordLength
var sw = Stopwatch.StartNew();
for (int i = 0; i < iterations; i++)
    analyzer.AverageWordLength();
sw.Stop();
Console.WriteLine($"AverageWordLength:   {sw.Elapsed.TotalMilliseconds,8:F2} ms total | {sw.Elapsed.TotalNanoseconds / iterations,8:F1} ns/op");

// Benchmark WordLengthHistogram
sw.Restart();
for (int i = 0; i < iterations; i++)
    analyzer.WordLengthHistogram();
sw.Stop();
Console.WriteLine($"WordLengthHistogram: {sw.Elapsed.TotalMilliseconds,8:F2} ms total | {sw.Elapsed.TotalNanoseconds / iterations,8:F1} ns/op");

// Benchmark UniqueWordCount
sw.Restart();
for (int i = 0; i < iterations; i++)
